def surveillance_readiness_check(
    cert: CertificationRecord,
    internal_audit_complete: bool,
    management_review_complete: bool,
    prior_corrective_actions: list[dict],
    scope_changes_since_last_audit: list[ScopeChangeEvent],
) -> dict:
    """
    Pre-surveillance readiness check. Returns a list of gaps.
    """
    gaps = []
    if not internal_audit_complete:
        gaps.append("Internal audit not completed since last surveillance")
    if not management_review_complete:
        gaps.append("Management review not completed since last surveillance")
    open_actions = [a for a in prior_corrective_actions if a.get("status") != "closed"]
    if open_actions:
        gaps.append(f"{len(open_actions)} corrective action(s) from prior audit still open")
    unnotified_changes = [c for c in scope_changes_since_last_audit
                          if c.requires_cb_notification and not c.cb_notified_at]
    if unnotified_changes:
        gaps.append(f"{len(unnotified_changes)} material scope change(s) not notified to CB")

    return {
        "ready": len(gaps) == 0,
        "gaps": gaps,
        "days_until_surveillance": cert.days_until_expiry()
        if cert.next_surveillance is None
        else (cert.next_surveillance - __import__("datetime").date.today()).days,
    }
